+        persistingSubscription = ApplicationState.RegisterOnPersisting(PersistEquipment);
+
+        if (!ApplicationState.TryTakeFromJson<List<InventoryApp.Services.EquipmentItem>>("equipment", out var restored))
+        {
+            equipment = await EquipmentService.GetEquipmentAsync();
